use crate::auth::traits::Authenticator; use crate::concurrency::ConcurrencyConfig; use crate::provider::extension::{ModelInfo, ProviderExtension}; use reqwest::Client; use serde::Deserialize;
pub struct OllamaExtension { base_url: String }
impl OllamaExtension { pub fn new() -> Self { Self { base_url: "http://127.0.0.1:11434/v1".to_string() } } pub fn with_base_url(mut self, url: impl Into<String>) -> Self { self.base_url = url.into().trim_end_matches('/').to_string(); self } }
impl Default for OllamaExtension { fn default() -> Self { Self::new() } }
#[derive(Debug, Deserialize)] struct OllamaModelList { data: Vec<OllamaModel> }
#[derive(Debug, Deserialize)] struct OllamaModel { id: String }
#[async_trait::async_trait] impl ProviderExtension for OllamaExtension { fn id(&self)->&str{"ollama"} async fn list_models(&self, h: &Client, a: &mut dyn Authenticator)->anyhow::Result<Vec<ModelInfo>>{ let url = format!("{}/models", self.base_url); let mut req = h.get(&url); req = a.inject(req)?; let res = req.send().await?; if !res.status().is_success() { return Ok(vec![ModelInfo{id:"llama3".to_string(),description:"Local Default".to_string()}]); } let list: OllamaModelList = match res.json().await { Ok(l) => l, Err(_) => return Ok(vec![ModelInfo{id:"llama3".to_string(),description:"Local Default".to_string()}]) }; let mut v = Vec::new(); for m in list.data { v.push(ModelInfo{id:m.id.clone(),description:m.id}); } Ok(v) } async fn get_balance(&self, _h: &Client, _a: &mut dyn Authenticator)->anyhow::Result<Option<crate::provider::balance::BalanceStatus>>{Ok(None)} fn concurrency_config(&self)->ConcurrencyConfig{ConcurrencyConfig{official_max:2, initial_limit:1, min_limit:1, max_limit:4, ..Default::default()}} }
